#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

__kernel void benchmark_func(class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);
  const size_t lid = get_local_id(0);
  const size_t lsize = get_local_size(0);
  const size_t group = get_group_id(0);
  const size_t num_groups = get_num_groups(0);

#ifdef BLOCK_STRIDED
  const size_t chunk_per_fusion = (size_t)ELEMENTS_PER_THREAD * lsize * num_groups;
  const size_t group_base = group * ((size_t)ELEMENTS_PER_THREAD * lsize);
#else
  const size_t chunk_per_fusion = (size_t)ELEMENTS_PER_THREAD * gsize;
#endif

  for (uint f = 0; f < (uint)FUSION_DEGREE; ++f) {
#ifdef BLOCK_STRIDED
    const size_t base = f * chunk_per_fusion + group_base + lid;
    for (uint i = 0; i < (uint)ELEMENTS_PER_THREAD; ++i) {
      const size_t idx = base + (size_t)i * lsize;
#else
    const size_t base = f * chunk_per_fusion + gid;
    for (uint i = 0; i < (uint)ELEMENTS_PER_THREAD; ++i) {
      const size_t idx = base + (size_t)i * gsize;
#endif
      class_T t = data[idx];

      for (uint j = 0; j < (uint)COMPUTE_ITERATIONS; ++j) {
        t = t * t + seed;
      }

      data[idx] = t;
    }
  }
}
